6	//! Async Vector Addition Example
7	//!
8	//! Demonstrates the cuda-async execution model:
9	//! - `#[cuda_module]` generates typed async launch methods
10	//! - `vecadd_async` returns a lazy `DeviceOperation`, no GPU work yet
11	//! - `.await` schedules it on a round-robin stream pool and waits
12	//! - `.sync()` does the same but blocks the calling thread
13	//! - `and_then` chains operations on the same stream
14	//! - `zip!` runs independent operations on the same stream
15	//!
16	//! Build and run with:
17	//!   cargo oxide run async_vecadd
18	
19	use cuda_device::{DisjointSlice, kernel, thread};
20	use cuda_host::cuda_module;
21	
22	// =============================================================================
23	// KERNEL -- compiled to PTX by rustc-codegen-cuda
24	// =============================================================================
25	
26	#[cuda_module]
27	mod kernels {
28	    use super::*;
29	
30	    #[kernel]
31	    pub fn vecadd(a: &[f32], b: &[f32], mut c: DisjointSlice<f32>) {
32	        let idx = thread::index_1d();
33	        let idx_raw = idx.get();
34	        if let Some(c_elem) = c.get_mut(idx) {
35	            *c_elem = a[idx_raw] + b[idx_raw];
36	        }
37	    }
38	}
39	
40	// =============================================================================
41	// HOST CODE -- compiled to native x86_64 by LLVM
42	// =============================================================================
43	
44	#[tokio::main]
45	async fn main() -> Result<(), Box<dyn std::error::Error>> {
46	    use cuda_async::device_box::DeviceBox;
47	    use cuda_async::device_context::init_device_contexts;
48	    use cuda_async::device_operation::DeviceOperation;
49	    use cuda_core::LaunchConfig;
50	    use cuda_core::memory::{malloc_async, memcpy_dtoh_async, memcpy_htod_async};
51	    use std::mem;
52	
53	    println!("=== Async Vector Addition (cuda-async) ===\n");
54	
55	    // 1. Initialize the async device context (round-robin pool of 4 streams).
56	    init_device_contexts(0, 1)?;
57	
58	    // 2. Load the embedded CUDA module from the async device context.
59	    let module = kernels::load_async(0)?;
60	
61	    const N: usize = 1024;
62	    let a_host: Vec<f32> = (0..N).map(|i| i as f32).collect();
63	    let b_host: Vec<f32> = (0..N).map(|i| (i * 2) as f32).collect();
64	
65	    println!("Input vectors (first 5 elements):");
66	    println!("  a = {:?}", &a_host[0..5]);
67	    println!("  b = {:?}", &b_host[0..5]);
68	
69	    // 3. Allocate device memory and copy host data.
70	    //    We use cuda_core memory APIs with the context's default stream.
71	    let (a_dev, b_dev, mut c_dev) = cuda_async::device_context::with_cuda_context(0, |ctx| {
72	        let stream = ctx.default_stream();
73	        let num_bytes = N * mem::size_of::<f32>();
74	
75	        unsafe {
76	            let a_dptr = malloc_async(stream.cu_stream(), num_bytes).unwrap();
77	            let b_dptr = malloc_async(stream.cu_stream(), num_bytes).unwrap();
78	            let c_dptr = malloc_async(stream.cu_stream(), num_bytes).unwrap();
79	
80	            memcpy_htod_async(a_dptr, a_host.as_ptr(), num_bytes, stream.cu_stream()).unwrap();
81	            memcpy_htod_async(b_dptr, b_host.as_ptr(), num_bytes, stream.cu_stream()).unwrap();
82	
83	            stream.synchronize().unwrap();
84	
85	            let a_dev = DeviceBox::<[f32]>::from_raw_parts(a_dptr, N, 0);
86	            let b_dev = DeviceBox::<[f32]>::from_raw_parts(b_dptr, N, 0);
87	            let c_dev = DeviceBox::<[f32]>::from_raw_parts(c_dptr, N, 0);
88	            (a_dev, b_dev, c_dev)
89	        }
90	    })?;
91	
92	    // 4. Launch the kernel asynchronously.
93	    //    `vecadd_async` returns an AsyncKernelLaunch (a DeviceOperation).
94	    //    No GPU work happens until we `.sync()` or `.await`.
95	    module
96	        .vecadd_async(
97	            LaunchConfig::for_num_elems(N as u32),
98	            &a_dev,
99	            &b_dev,
100	            &mut c_dev,
101	        )?
102	        .sync()?;
103	
104	    // 5. Copy results back.
105	    let mut c_host = vec![0.0f32; N];
106	    cuda_async::device_context::with_cuda_context(0, |ctx| {
107	        let stream = ctx.default_stream();
108	        unsafe {
109	            memcpy_dtoh_async(
110	                c_host.as_mut_ptr(),
111	                c_dev.cu_deviceptr(),
112	                N * mem::size_of::<f32>(),
113	                stream.cu_stream(),
114	            )
115	            .unwrap();
116	            stream.synchronize().unwrap();
117	        }
118	    })?;
119	
120	    println!("\nOutput vector (first 5 elements):");
121	    println!("  c = {:?}", &c_host[0..5]);
122	
123	    // 6. Verify.
124	    let mut errors = 0;
125	    for i in 0..N {
126	        let expected = a_host[i] + b_host[i];
127	        if (c_host[i] - expected).abs() > 1e-5 {
128	            if errors < 5 {
129	                eprintln!(
130	                    "  Error at [{}]: expected {}, got {}",
131	                    i, expected, c_host[i]
132	                );
133	            }
134	            errors += 1;
135	        }
136	    }
137	
138	    if errors == 0 {
139	        println!("\nSUCCESS: All {} elements correct!", N);
140	    } else {
141	        println!("\nFAILED: {} errors", errors);
142	        std::process::exit(1);
143	    }
144	
145	    Ok(())
146	}
