146	
147	        let atomic_counter = unsafe { &*(counter.as_ptr() as *const DeviceAtomicU32) };
148	
149	        // AcqRel triggers: fence release + atomicrmw monotonic + fence acquire
150	        let old = atomic_counter.fetch_add(1, AtomicOrdering::AcqRel);
151	
152	        if let Some(out_elem) = out.get_mut(gid) {
153	            *out_elem = old;
154	        }
155	    }
