171	// HOST CODE
172	// =============================================================================
173	
174	fn main() -> Result<(), Box<dyn std::error::Error>> {
175	    println!("=== Typed Closure Kernel Test ===\n");
176	
177	    let ctx = CudaContext::new(0)?;
178	    let stream = ctx.default_stream();
179	
180	    const N: usize = 1024;
181	    let input_data: Vec<f32> = (0..N).map(|i| i as f32).collect();
182	
183	    let input_dev = DeviceBuffer::from_host(&stream, &input_data)?;
184	    let mut output_dev: DeviceBuffer<f32>;
185	
186	    let module = load_kernel_module(&ctx, "host_closure")
187	        .map_err(|err| format!("failed to load host_closure kernel module: {err}"))?;
188	    let typed_module = kernels::from_module(module.clone())
189	        .map_err(|err| format!("failed to initialize typed host_closure module: {err}"))?;
190	    use kernels::*;
191	
192	    let mut failed = false;
193	
194	    macro_rules! run_launch_matrix {
195	        (
196	            $label:literal,
197	            $kernel:path,
198	            $typed_method:ident,
199	            $typed_async_method:ident,
200	            $closure:expr,
201	            $expected:expr,
202	            $tolerance:expr
203	        ) => {{
204	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
205	            // SAFETY: closure-then-slices matches every kernel this matrix
206	            // launches (closure env, input slice, output slice); both buffers
207	            // are live DeviceBuffers and the closure's captures are
208	            // host-accessible via HMM.
209	            unsafe {
210	                cuda_launch! {
211	                    kernel: $kernel,
212	                    stream: stream,
213	                    module: module,
214	                    config: LaunchConfig::for_num_elems(N as u32),
215	                    args: [$closure, slice(input_dev), slice_mut(output_dev)]
216	                }
217	            }?;
218	            let output_host = output_dev.to_host_vec(&stream)?;
219	            verify_output(
220	                concat!("cuda_launch ", $label),
221	                &output_host,
222	                &input_data,
223	                $tolerance,
224	                $expected,
225	                &mut failed,
226	            );
227	
228	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
229	            typed_module.$typed_method::<f32, _>(
230	                stream.as_ref(),
231	                LaunchConfig::for_num_elems(N as u32),
232	                $closure,
233	                &input_dev,
234	                &mut output_dev,
235	            )?;
236	            let output_host = output_dev.to_host_vec(&stream)?;
237	            verify_output(
238	                concat!("typed launch ", $label),
239	                &output_host,
240	                &input_data,
