261	                &mut failed,
262	            );
263	
264	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
265	            typed_module
266	                .$typed_async_method::<f32, _>(
267	                    LaunchConfig::for_num_elems(N as u32),
268	                    $closure,
269	                    &input_dev,
270	                    &mut output_dev,
271	                )?
272	                .sync_on(&stream)?;
273	            let output_host = output_dev.to_host_vec(&stream)?;
274	            verify_output(
275	                concat!("typed async launch ", $label),
276	                &output_host,
277	                &input_data,
278	                $tolerance,
279	                $expected,
