531	    // =========================================================================
532	    // TEST 12: #[repr(C)] struct capture (identity-order layout)
533	    // =========================================================================
534	    // Counterpart to test 8: the layout fix has to handle both the reordered
535	    // case (default Rust repr, fields packed by size) and the identity-order
536	    // case (`#[repr(C)]`, fields kept in declaration order). The closure
537	    // body is the same as test 8 so the expected output is comparable.
538	    println!("Test 12: #[repr(C)] struct capture (identity-order layout)");
539	    {
540	        let mixed = ReprCMixed {
541	            small: 9,
542	            wide: 2.25,
